  1→/**
  2→ * Contact API Client
  3→ *
  4→ * TypeScript client for Contact API with fetch wrapper.
  5→ * Provides typed methods for CRUD operations on contacts.
  6→ */
  7→
  8→import type {
  9→  ContactData,
 10→  ContactListParams,
 11→  ContactCreateInput,
 12→  ContactUpdateInput,
 13→  ApiListResponse,
 14→  ApiResponse,
 15→  ApiClientConfig,
 16→} from './types';
 17→import { ApiClientError, parseApiError, parseJson } from './shared';
 18→
 19→export { ApiClientError } from './shared';
 20→
 21→/**
 22→ * Default base URL for API requests
 23→ */
 24→const DEFAULT_BASE_URL = '/api';
 25→
 26→/**
 27→ * Contact API Client
 28→ *
 29→ * Provides typed methods for Contact CRUD operations.
 30→ * All methods return typed data or throw ApiClientError.
 31→ */
 32→export class ContactApiClient {
 33→  private baseUrl: string;
 34→  private fetchFn: typeof globalThis.fetch;
 35→  private defaultHeaders: Record<string, string>;
 36→
 37→  constructor(config: ApiClientConfig = {}) {
 38→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 39→    this.fetchFn = config.fetch ?? fetch;
 40→    this.defaultHeaders = {
 41→      'Content-Type': 'application/json',
 42→      ...config.headers,
 43→    };
 44→  }
 45→
 46→  /**
 47→   * Build full URL for endpoint
 48→   */
 49→  private url(path: string, params?: Record<string, string | undefined>): string {
 50→    const fullUrl = `${this.baseUrl}${path}`;
 51→
 52→    if (params) {
 53→      const searchParams = new URLSearchParams();
 54→      for (const [key, value] of Object.entries(params)) {
 55→        if (value !== undefined) {
 56→          searchParams.append(key, value);
 57→        }
 58→      }
 59→      const queryString = searchParams.toString();
 60→      if (queryString) {
 61→        return `${fullUrl}?${queryString}`;
 62→      }
 63→    }
 64→
 65→    return fullUrl;
 66→  }
 67→
 68→  /**
 69→   * GET /api/contacts
 70→   *
 71→   * List all contacts with optional filtering.
 72→   * Supports filtering by type and status.
 73→   *
 74→   * @returns Array of contacts with count
 75→   */
 76→  async getContacts(params?: ContactListParams): Promise<ApiListResponse<ContactData>> {
 77→    const response = await this.fetchFn(
 78→      this.url('/contacts', {
 79→        type: params?.type,
 80→        status: params?.status,
 81→      }),
 82→      {
 83→        headers: this.defaultHeaders,
 84→      }
 85→    );
 86→
 87→    if (!response.ok) {
 88→      return parseApiError(response);
 89→    }
 90→
 91→    return parseJson<ApiListResponse<ContactData>>(response);
 92→  }
 93→
 94→  /**
 95→   * GET /api/contacts/[id]
 96→   *
 97→   * Fetch a single contact by ID.
 98→   *
 99→   * @param id - Contact UUID
100→   * @returns Contact data
101→   * @throws ApiClientError with 404 if not found
102→   */
103→  async getContact(id: string): Promise<ApiResponse<ContactData>> {
104→    if (!id) {
105→      throw new ApiClientError(400, 'Validation failed', 'id is required');
106→    }
107→
108→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
109→      headers: this.defaultHeaders,
110→    });
111→
112→    if (!response.ok) {
113→      return parseApiError(response);
114→    }
115→
116→    return parseJson<ApiResponse<ContactData>>(response);
117→  }
118→
119→  /**
120→   * POST /api/contacts
121→   *
122→   * Create a new contact.
123→   * Validates required fields based on contact type.
124→   *
125→   * @param data - Contact creation input
126→   * @returns Created contact data
127→   * @throws ApiClientError with 400 on validation errors
128→   */
129→  async createContact(data: ContactCreateInput): Promise<ApiResponse<ContactData>> {
130→    const response = await this.fetchFn(this.url('/contacts'), {
131→      method: 'POST',
132→      headers: this.defaultHeaders,
133→      body: JSON.stringify(data),
134→    });
135→
136→    if (!response.ok) {
137→      return parseApiError(response);
138→    }
139→
140→    return parseJson<ApiResponse<ContactData>>(response);
141→  }
142→
143→  /**
144→   * PUT /api/contacts/[id]
145→   *
146→   * Update an existing contact.
147→   * Only provided fields are updated (partial update).
148→   *
149→   * @param id - Contact UUID
150→   * @param data - Contact update input (all fields optional)
151→   * @returns Updated contact data
152→   * @throws ApiClientError with 404 if contact not found
153→   */
154→  async updateContact(
155→    id: string,
156→    data: ContactUpdateInput
157→  ): Promise<ApiResponse<ContactData>> {
158→    if (!id) {
159→      throw new ApiClientError(400, 'Validation failed', 'id is required');
160→    }
161→
162→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
163→      method: 'PUT',
164→      headers: this.defaultHeaders,
165→      body: JSON.stringify(data),
166→    });
167→
168→    if (!response.ok) {
169→      return parseApiError(response);
170→    }
171→
172→    return parseJson<ApiResponse<ContactData>>(response);
173→  }
174→
175→  /**
176→   * DELETE /api/contacts/[id]
177→   *
178→   * Soft-delete a contact by setting deletedAt timestamp.
179→   * Contact remains in database but is filtered from queries.
180→   *
181→   * @param id - Contact UUID
182→   * @returns Deleted contact data with success message
183→   * @throws ApiClientError with 404 if contact not found
184→   */
185→  async deleteContact(id: string): Promise<ApiResponse<ContactData> & { message: string }> {
186→    if (!id) {
187→      throw new ApiClientError(400, 'Validation failed', 'id is required');
188→    }
189→
190→    const response = await this.fetchFn(this.url(`/contacts/${id}`), {
191→      method: 'DELETE',
192→      headers: this.defaultHeaders,
193→    });
194→
195→    if (!response.ok) {
196→      return parseApiError(response);
197→    }
198→
199→    return parseJson<ApiResponse<ContactData> & { message: string }>(response);
200→  }
201→}
202→
203→/**
204→ * Default singleton instance for use across the application
205→ */
206→export const contactsApi = new ContactApiClient();
207→
208→/**
209→ * Convenience exports for direct use
210→ */
211→export const {
212→  getContacts,
213→  getContact,
214→  createContact,
215→  updateContact,
216→  deleteContact,
217→} = contactsApi;
218→
219→export default contactsApi;
220→

 1→/**
 2→ * Shared API Client Helpers
 3→ *
 4→ * parseApiError, parseJson, and ApiClientError used by all API clients.
 5→ */
 6→
 7→import type { ApiError } from './types';
 8→
 9→/**
10→ * API client error class
11→ */
12→export class ApiClientError extends Error {
13→  constructor(
14→    public statusCode: number,
15→    public error: string,
16→    public message: string
17→  ) {
18→    super(`${error}: ${message}`);
19→    this.name = 'ApiClientError';
20→  }
21→}
22→
23→/**
24→ * Parse and throw API error from response
25→ */
26→export async function parseApiError(response: Response): Promise<never> {
27→  let error: ApiError;
28→
29→  try {
30→    error = await response.json();
31→  } catch {
32→    error = {
33→      error: 'Unknown error',
34→      message: response.statusText || 'Failed to parse error response',
35→    };
36→  }
37→
38→  console.error('API request failed:', response.status, error);
39→  throw new ApiClientError(response.status, error.error, error.message);
40→}
41→
42→/**
43→ * Validate response is JSON and parse it
44→ */
45→export async function parseJson<T>(response: Response): Promise<T> {
46→  const contentType = response.headers.get('content-type');
47→  if (!contentType?.includes('application/json')) {
48→    console.error('Unexpected content-type:', contentType);
49→    throw new ApiClientError(
50→      response.status,
51→      'Invalid response',
52→      'Expected JSON response but got ' + (contentType || 'no content-type')
53→    );
54→  }
55→
56→  return response.json() as Promise<T>;
57→}
